// GetComment returns the comment for a descriptor by its full name
func GetComment(fullName string) string {
	return Comments[fullName]
}

// GetCommentForField returns the comment for a field descriptor
func GetCommentForField(fd protoreflect.FieldDescriptor) string {
	return GetComment(string(fd.FullName()))
}

// GetCommentForMessage returns the comment for a message descriptor
func GetCommentForMessage(md protoreflect.MessageDescriptor) string {
	return GetComment(string(md.FullName()))
}

// GetCommentForEnum returns the comment for an enum descriptor
func GetCommentForEnum(ed protoreflect.EnumDescriptor) string {
	return GetComment(string(ed.FullName()))
}

// GetCommentForEnumValue returns the comment for an enum value descriptor
func GetCommentForEnumValue(evd protoreflect.EnumValueDescriptor) string {
	return GetComment(string(evd.FullName()))
}
